fn calculate_price_of_apples(quantity: i32) -> i32 {
    if quantity > 40 {
        quantity
    } else {
        quantity * 2
    }
}

fn main() {
    let price1 = calculate_price_of_apples(35);
    println!("35 apples cost {} cents", price1);
    assert_eq!(price1, 70);

    let price2 = calculate_price_of_apples(65);
    println!("65 apples cost {} cents", price2);
    assert_eq!(price2, 65);
}
